import { useState } from 'react';
import styles from '../styles/WaafooComingSoon.module.css';
import '../styles/global.css';
import PhoneCard from './PhoneCard';
import TdsChip from './TdsChip';
import {
  CheckIcon,
  LinkedinIcon,
  FacebookIcon,
  InstagramIcon,
} from './Icons';

const LOGO_ICON = 'data:image/png;base64,';
const LOGO_TEXT = 'data:image/png;base64,';

const SOCIALS = [
  { label: 'Linkedin',  Icon: LinkedInIcon  },
  { label: 'Facebook',  Icon: FacebookIcon  },
  { label: 'Instagram', Icon: InstagramIcon },
];

export default function WaafooComingSoon() {
  const [email, setEmail]         = useState('');
  const [submitted, setSubmitted] = useState(false);
  const [error, setError]         = useState(false);

  const handleSubmit = () => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!re.test(email.trim())) {
      setError(true);
      setTimeout(() => setError(false), 1200);
      return;
    }
    setSubmitted(true);
  };

  return (
    <>
      {/* Background blobs */}
      <div className={styles.blob1} />
      <div className={styles.blob2} />

      {/* ── NAV ── */}
      <nav className={styles.nav}>
        <div className={styles.navLogo}>
          <img className={styles.navIcon} src={LOGO_ICON} alt="Waafoo icon" />
          <img className={styles.navTextLogo} src={LOGO_TEXT} alt="Waafoo" />
        </div>
      </nav>

      {/* ── MAIN ── */}
      <main className={styles.main}>

        {/* LEFT */}
        <div className={styles.leftCol}>
          <div className={styles.comingSoonTag}>Coming Soon</div>

          <h1 className={styles.headline}>
            Get Notified<br />
            When We <span className={styles.accent}>Launch</span>
          </h1>

          {!submitted ? (
            <>
              <div className={`${styles.emailFormWrap}${error ? ' ' + styles.error : ''}`}>
                <input
                  className={styles.emailInput}
                  type="email"
                  placeholder="Enter your email address"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
                />
                <button className={styles.notifyBtn} onClick={handleSubmit}>
                  Notify Me
                </button>
              </div>
              <p className={styles.spamNote}>*Don't worry, we will not spam you :)</p>
            </>
          ) : (
            <div className={styles.successMsg}>
              <CheckIcon />
              You're on the list! We'll reach out soon.
            </div>
          )}
        </div>

        {/* RIGHT */}
        <div className={styles.rightCol}>
          <div className={styles.orbBg} />
          <PhoneCard />
          <TdsChip />
        </div>

      </main>

      {/* ── FOOTER ── */}
      <footer className={styles.footer}>
        <div className={styles.footerSocials}>
          {SOCIALS.map(({ label, Icon }) => (
            <a key={label} href="#" className={styles.socialBtn} aria-label={label}>
              <Icon />
            </a>
          ))}
        </div>
        <div className={styles.footerLinks}>
          <a href="mailto:connect@waafoo.in" className={styles.footerLink}>
            Email Us
          </a>
        </div>
      </footer>
    </>
  );
}
